formulas.expression:
CASE( 
   /* ------------------------------------------------------------------ */
   /* REPLACEMENT 1: Logic for Product_Compatibility_Fromula__c          */
   /* Calculate: If Amendment is blank, use Base, otherwise use Amendment */
   /* ------------------------------------------------------------------ */
   IF( ISBLANK(TEXT({!$Record.Product_Compatibility_Amendment__c})), 
       TEXT({!$Record.Product_Compatibility__c}), 
       TEXT({!$Record.Product_Compatibility_Amendment__c})
   ), 

   /* Matches for the calculated value above */
   "Bis4.0", "Similarweb 4.0",
   "TSM", "TSM",
   "Admetricks", "Admetricks",
   "NewsleverM", "Newslever",
   "NewsleverY", "Newslever",

   /* ------------------------------------------------------------------ */
   /* ELSE: Complex Logic                                                */
   /* ------------------------------------------------------------------ */
   IF( AND( {!$Profile.Name} = 'SW SalesOps Extended', NOT({!$Record.zqu__Opportunity__r.New_guided_flow__c}) ), "Salesops Flow",

     IF( AND( 
          ISPICKVAL({!$Record.zqu__Account__r.AccountSource}, "42matters"), 
          ISPICKVAL({!$Record.Product_Compatibility__c}, '42matters'), 
          NOT(ISPICKVAL({!$Record.Migrating_to_New_Soultion__c}, 'Yes'))
         ), "42matters",

       IF( OR( 
            ISPICKVAL({!$Record.New_solution_use_case__c}, 'No Touch Packages'), 
            ISPICKVAL({!$Record.Product_Type_Amendment__c}, 'No Touch Packages')
           ), 'No Touch Addons',

           /* ------------------------------------------------------------------ */
           /* REPLACEMENT 2: Logic for Is_Country_Mandatory__c                   */
           /* We check if the calculated result equals 'Only add on steps'       */
           /* ------------------------------------------------------------------ */
           IF( 
             CASE( 
               /* Inner Logic: Determine which field to check (Migration vs Standard) */
               IF( ISPICKVAL({!$Record.Migrating_to_New_Soultion__c}, "Yes"), 
                   TEXT({!$Record.Product_Compatibility_Amendment__c}), 
                   TEXT({!$Record.Product_Compatibility__c}) 
               ),
               /* List of values that return 'Only add on steps' */
               "RankRanger", "Only add on steps",
               "StockInt", "Only add on steps",
               "ShopInt", "Only add on steps",
               "Admetricks", "Only add on steps",
               "AppIn", "Only add on steps",
               "FRO", "Only add on steps",
               "SalesLeadEnrichment", "Only add on steps",
               "SalesStarter2.0", "Only add on steps",
               "42matters", "Only add on steps",
               "MC", "Only add on steps",
               "DF", "Only add on steps",

               /* Default: */
               "No validation needed"
             ) = 'Only add on steps', 

             "Only Similarweb Addons", 
             "Similarweb Addons"
           )
           /* ------------------------------------------------------------------ */

       )
     )
   )
)


IF ( ISPICKVAL({!Get_payment_method.Zuora__Type__c}, "ACH"), "ACH",
IF ( ISPICKVAL({!Get_payment_method.Zuora__Type__c}, "BankTransfer"), "Bank Transfer",
IF ( ISPICKVAL({!Get_payment_method.Zuora__Type__c}, "Cash"), "Cash",
IF ( ISPICKVAL({!Get_payment_method.Zuora__Type__c}, "Check"), "Check",
IF ( ISPICKVAL({!Get_payment_method.Zuora__Type__c}, "CreditCard"), "Credit Card",
IF ( ISPICKVAL({!Get_payment_method.Zuora__Type__c}, "CreditCardReferenceTransaction"), "Credit Card Reference Transaction",
IF ( ISPICKVAL({!Get_payment_method.Zuora__Type__c}, "DebitCard"), "Debit Card",
IF ( ISPICKVAL({!Get_payment_method.Zuora__Type__c}, "Other"), "Other",
IF ( ISPICKVAL({!Get_payment_method.Zuora__Type__c}, "PayPal"), "PayPal",
IF ( ISPICKVAL({!Get_payment_method.Zuora__Type__c}, "WireTransfer"), "Wire Transfer", ""
)
)
)
)
)
)
)
)
))
